package com.trademaster.ims.mobile.checkout.model;
import jakarta.persistence.*;import java.math.BigDecimal;
@Entity @Table(name="customer_order_items")public class CustomerOrderItem{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="order_id",nullable=false)private Long orderId;@Column(name="product_id",nullable=false)private Long productId;@Column(name="variation_id")private Long variationId;@Column(name="product_name",nullable=false)private String productName;@Column(name="product_code",nullable=false)private String productCode;@Column(name="variation_name")private String variationName;@Column(name="image_url",length=500)private String imageUrl;@Column(name="unit_price",nullable=false,precision=15,scale=2)private BigDecimal unitPrice;@Column(nullable=false)private int quantity;@Column(name="tax_rate",nullable=false,precision=7,scale=4)private BigDecimal taxRate;@Column(name="tax_amount",nullable=false,precision=15,scale=2)private BigDecimal taxAmount;@Column(name="line_subtotal",nullable=false,precision=15,scale=2)private BigDecimal lineSubtotal;
 public Long getId(){return id;}public Long getOrderId(){return orderId;}public Long getProductId(){return productId;}public Long getVariationId(){return variationId;}public String getProductName(){return productName;}public String getProductCode(){return productCode;}public String getVariationName(){return variationName;}public String getImageUrl(){return imageUrl;}public BigDecimal getUnitPrice(){return unitPrice;}public int getQuantity(){return quantity;}public BigDecimal getTaxRate(){return taxRate;}public BigDecimal getTaxAmount(){return taxAmount;}public BigDecimal getLineSubtotal(){return lineSubtotal;}public void setOrderId(Long v){orderId=v;}public void setProductId(Long v){productId=v;}public void setVariationId(Long v){variationId=v;}public void setProductName(String v){productName=v;}public void setProductCode(String v){productCode=v;}public void setVariationName(String v){variationName=v;}public void setImageUrl(String v){imageUrl=v;}public void setUnitPrice(BigDecimal v){unitPrice=v;}public void setQuantity(int v){quantity=v;}public void setTaxRate(BigDecimal v){taxRate=v;}public void setTaxAmount(BigDecimal v){taxAmount=v;}public void setLineSubtotal(BigDecimal v){lineSubtotal=v;}}
